import { API_URL } from '../config.js';

const OFF_PROXY_BASE = `${API_URL}/api/sections/health/openfoodfacts`;

export interface OFFProduct {
    product_name: string;
    brands?: string;
    image_url?: string;
    barcode?: string;
    calories_per_100g: number;
    protein_per_100g: number;
    carbs_per_100g: number;
    fat_per_100g: number;
    fiber_per_100g: number;
    sugar_per_100g: number;
    sodium_per_100g: number;
    serving_size?: string;
    serving_quantity?: number;
    quantity?: string;
    product_quantity?: number;
    categories_tags?: string[];
    countries_tags?: string[];
}

export interface OFFSearchPage {
    items: OFFProduct[];
    page: number;
    pageCount: number;
    totalCount: number;
}

export interface ServingNutrition {
    calories: number;
    protein_g: number;
    carbs_g: number;
    fat_g: number;
    fiber_g: number;
    sugar_g: number;
    sodium_mg: number;
}

function parseNutriments(nutriments: Record<string, number | undefined>): Omit<OFFProduct, 'product_name' | 'brands' | 'image_url' | 'barcode'> {
    return {
        calories_per_100g: nutriments['energy-kcal_100g'] ?? 0,
        protein_per_100g: nutriments['proteins_100g'] ?? 0,
        carbs_per_100g: nutriments['carbohydrates_100g'] ?? 0,
        fat_per_100g: nutriments['fat_100g'] ?? 0,
        fiber_per_100g: nutriments['fiber_100g'] ?? 0,
        sugar_per_100g: nutriments['sugars_100g'] ?? 0,
        sodium_per_100g: nutriments['sodium_100g'] ?? 0,
    };
}

function pickProductName(p: any): string {
    return (p.product_name || p.product_name_en || p.product_name_nl || p.product_name_de || 'Unknown Product').trim();
}

export class OpenFoodFactsService {
    static async lookupBarcode(barcode: string): Promise<OFFProduct | null> {
        try {
            const response = await fetch(`${OFF_PROXY_BASE}/product/${barcode}`);
            if (!response.ok) return null;

            const data = await response.json();
            if (data.status !== 1 || !data.product) return null;

            const p = data.product;
            return {
                product_name: pickProductName(p),
                brands: p.brands || undefined,
                image_url: p.image_front_url || undefined,
                barcode,
                serving_size: p.serving_size || undefined,
                serving_quantity: typeof p.serving_quantity === 'number' ? p.serving_quantity : undefined,
                quantity: p.quantity || undefined,
                product_quantity: typeof p.product_quantity === 'number' ? p.product_quantity
                    : typeof p.product_quantity === 'string' ? parseFloat(p.product_quantity) || undefined
                        : undefined,
                categories_tags: Array.isArray(p.categories_tags) ? p.categories_tags : undefined,
                ...parseNutriments(p.nutriments ?? {}),
            };
        } catch {
            return null;
        }
    }

    static async searchFood(query: string, options?: { signal?: AbortSignal; page?: number }): Promise<OFFSearchPage> {
        const page = options?.page ?? 1;
        try {
            const params = new URLSearchParams({
                q: query,
                page_size: '50',
                page: page.toString(),
            });
            const response = await fetch(`${OFF_PROXY_BASE}/search?${params}`, {
                signal: options?.signal,
            });
            if (!response.ok) {
                throw new Error(`Open Food Facts search failed: ${response.statusText}`);
            }

            const data = await response.json();
            if (!data.products || !Array.isArray(data.products)) {
                return { items: [], page, pageCount: 0, totalCount: 0 };
            }

            const products = data.products.map((p: any): OFFProduct => ({
                product_name: pickProductName(p),
                brands: p.brands || undefined,
                image_url: p.image_front_url || undefined,
                barcode: p.code || undefined,
                serving_size: p.serving_size || undefined,
                serving_quantity: typeof p.serving_quantity === 'number' ? p.serving_quantity : undefined,
                quantity: p.quantity || undefined,
                product_quantity: typeof p.product_quantity === 'number' ? p.product_quantity
                    : typeof p.product_quantity === 'string' ? parseFloat(p.product_quantity) || undefined
                        : undefined,
                categories_tags: Array.isArray(p.categories_tags) ? p.categories_tags : undefined,
                countries_tags: Array.isArray(p.countries_tags) ? p.countries_tags : undefined,
                ...parseNutriments(p.nutriments ?? {}),
            }));

            const ranked = this.rankByRelevance(products, query);

            // Page 1: promote Dutch-country products to the top of the list so the user
            // sees familiar supermarket brands first. Subsequent pages just use the ranked
            // list as-is, so "Load More" expands with progressively more global results.
            let items: OFFProduct[];
            if (page === 1) {
                const dutch = ranked.filter(p => p.countries_tags?.includes('en:netherlands'));
                const dutchBarcodes = new Set(dutch.map(p => p.barcode));
                const rest = ranked.filter(p => !dutchBarcodes.has(p.barcode));
                items = [...dutch, ...rest];
            } else {
                items = ranked;
            }

            return {
                items,
                page,
                pageCount: typeof data.page_count === 'number' ? data.page_count : 0,
                totalCount: typeof data.count === 'number' ? data.count : items.length,
            };
        } catch (error) {
            if (error instanceof Error && error.name === 'AbortError') {
                return { items: [], page, pageCount: 0, totalCount: 0 };
            }
            throw error;
        }
    }

    /**
     * Score products by relevance to the query. Prefers:
     * - Products where query words appear in the product name (not just ingredients)
     * - Shorter product names (more likely to be the actual product, not a variant)
     * - Product names that start with the query
     */
    static rankByRelevance(products: OFFProduct[], query: string): OFFProduct[] {
        const queryLower = query.toLowerCase().trim();
        const words = queryLower.split(/\s+/).filter(w => w.length > 1);
        if (words.length === 0) return products;

        return products
            .map(p => {
                const name = p.product_name.toLowerCase();
                const brands = (p.brands ?? '').toLowerCase();
                const nameAndBrands = (name + ' ' + brands);
                const nameWords = name.split(/\s+/);

                // Base: how many query words appear in name+brands
                const matches = words.filter(w => nameAndBrands.includes(w)).length;
                if (matches === 0) return { product: p, score: 0 };

                let score = matches * 10;

                // Massive bonus for exact name match (raw ingredients often just named "Apple")
                if (name === queryLower) score += 50;

                // Bonus: query words that match as whole words in the product name
                const wholeWordMatches = words.filter(w => nameWords.some(nw => nw === w || nw.startsWith(w))).length;
                score += wholeWordMatches * 5;

                // Bonus: product name starts with the query
                if (name.startsWith(queryLower)) score += 15;

                // Bonus: short product names are more likely to be the base product
                // (e.g., "Banana" scores higher than "Banana Chocolate Milkshake Deluxe")
                if (nameWords.length <= 1) score += 20; // Single word items are very likely raw ingredients
                else if (nameWords.length <= 3) score += 8;
                else if (nameWords.length <= 5) score += 4;

                // Bonus for "clean" brands (generic products often have no brand or brand same as name)
                if (!p.brands || brands === name) score += 10;

                // Bonus for raw ingredient categories
                const isRaw = p.categories_tags?.some(t =>
                    t.includes('raw') ||
                    t.includes('fresh-') ||
                    t.includes('fruits') ||
                    t.includes('vegetables') ||
                    t.includes('eggs')
                );
                if (isRaw) score += 15;

                return { product: p, score };
            })
            .sort((a, b) => b.score - a.score)
            .filter(r => r.score > 0)
            .map(r => r.product);
    }

    /**
     * Calculate nutrition values for a given serving size in grams.
     * Formula: (nutrient per 100g × grams) / 100
     * Sodium is converted from g to mg in the output.
     */
    static calculateServing(product: Pick<OFFProduct, 'calories_per_100g' | 'protein_per_100g' | 'carbs_per_100g' | 'fat_per_100g' | 'fiber_per_100g' | 'sugar_per_100g' | 'sodium_per_100g'>, grams: number): ServingNutrition {
        const scale = (val: number) => Math.round((val * grams / 100) * 100) / 100;
        return {
            calories: scale(product.calories_per_100g),
            protein_g: scale(product.protein_per_100g),
            carbs_g: scale(product.carbs_per_100g),
            fat_g: scale(product.fat_per_100g),
            fiber_g: scale(product.fiber_per_100g),
            sugar_g: scale(product.sugar_per_100g),
            sodium_mg: scale(product.sodium_per_100g * 1000),
        };
    }

    /**
     * Determine a sensible default serving size (in grams) for a product.
     * Priority:
     * 1. Drinks (beverages category): full container (product_quantity)
     * 2. serving_quantity if available (numeric serving grams from OFF)
     * 3. Parse serving_size string for a numeric value
     * 4. Fallback: 100g
     */
    static getDefaultServing(product: OFFProduct): number {
        const isBeverage = product.categories_tags?.some(t => t.includes('beverage') || t.includes('drink') || t.includes('juice') || t.includes('milk') || t.includes('water'));

        // For beverages, prefer full container size
        if (isBeverage && product.product_quantity && product.product_quantity > 0) {
            return Math.round(product.product_quantity);
        }

        // Use serving_quantity if available (this is the per-serving weight from OFF)
        if (product.serving_quantity && product.serving_quantity > 0) {
            return Math.round(product.serving_quantity);
        }

        // Try to parse serving_size string, e.g. "30g", "1 bar (45g)", "250ml"
        if (product.serving_size) {
            const parsed = this.parseServingSize(product.serving_size);
            if (parsed > 0) return Math.round(parsed);
        }

        // For non-beverage products with a small package, use full package
        if (product.product_quantity && product.product_quantity > 0 && product.product_quantity <= 100) {
            return Math.round(product.product_quantity);
        }

        return 100;
    }

    /** Parse a serving_size string like "30g", "1 bar (45g)", "250 ml" into grams */
    static parseServingSize(serving: string): number {
        // Try parenthesized value first: "1 bar (45g)" → 45
        const parenMatch = serving.match(/\((\d+(?:\.\d+)?)\s*(?:g|ml)\)/i);
        if (parenMatch) return parseFloat(parenMatch[1]);

        // Try plain value: "30g", "250 ml", "100g"
        const plainMatch = serving.match(/(\d+(?:\.\d+)?)\s*(?:g|ml)\b/i);
        if (plainMatch) return parseFloat(plainMatch[1]);

        // Try just a number
        const numMatch = serving.match(/(\d+(?:\.\d+)?)/);
        if (numMatch) return parseFloat(numMatch[1]);

        return 0;
    }

    /**
     * Get a sensible step increment for adjusting serving size.
     * Adapts to the current serving weight.
     */
    static getServingStep(currentGrams: number): number {
        if (currentGrams <= 50) return 5;
        if (currentGrams <= 200) return 25;
        if (currentGrams <= 500) return 50;
        return 100;
    }

    /**
     * Get quick-select portion presets based on the default serving size.
     * Returns array of { label, grams } objects.
     */
    static getPortionPresets(defaultGrams: number): { multiplier: number; grams: number }[] {
        return [
            { multiplier: 0.5, grams: Math.round(defaultGrams * 0.5) },
            { multiplier: 1.5, grams: Math.round(defaultGrams * 1.5) },
            { multiplier: 2, grams: defaultGrams * 2 },
        ];
    }
}
