const MACRO_INPUT_IDS = ['cal-serving', 'protein-serving', 'carbs-serving', 'fat-serving', 'fiber-serving', 'sugar-serving'] as const;

export class FoodServingForm extends HTMLElement {
    private _data: FoodServingFormData | null = null;
    private _editable = false;
    private _initialized = false;
    /** Serving amount at the last render/scale point — used for ratio scaling in edit mode. */
    private _lastServingAmount = 100;

    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
    }

    static get observedAttributes(): string[] {
        return ['editable'];
    }

    attributeChangedCallback(name: string, _old: string | null, value: string | null): void {
        if (name === 'editable') {
            this._editable = value !== null;
            if (this._initialized) this.rebuild();
        }
    }

    connectedCallback(): void {
        if (this.hasOwnProperty('data')) {
            const value = (this as any).data;
            delete (this as any).data;
            this._data = value;
        }
        this._editable = this.hasAttribute('editable');
        this.rebuild();
        this._initialized = true;
    }

    set data(value: FoodServingFormData) {
        this._data = value;
        this.populate();
    }

    /**
     * Read current serving values and amount from the form. `servingAmount`
     * is returned in BASE UNITS (grams in weight mode; servings × baseAmount
     * otherwise) — the unit every persisted amount uses (story 192). The
     * displayed serving count is a UI affordance only.
     */
    getCurrentValues(): { servingAmount: number; serving: ServingValues } {
        const shadow = this.shadowRoot!;
        const inputAmount = Math.max(0.1, Number.parseFloat(
            (shadow.getElementById('serving-size') as HTMLInputElement).value
        ) || 0.1);
        const servingAmount = this._data?.servingByWeight === false
            ? inputAmount * (this._data.baseAmount > 0 ? this._data.baseAmount : 1)
            : inputAmount;

        if (this._editable) {
            return {
                servingAmount,
                serving: {
                    calories: this.readFloatInput('cal-serving'),
                    protein_g: this.readFloatInput('protein-serving'),
                    carbs_g: this.readFloatInput('carbs-serving'),
                    fat_g: this.readFloatInput('fat-serving'),
                    fiber_g: this.readFloatInput('fiber-serving'),
                    sugar_g: this.readFloatInput('sugar-serving'),
                    // Sodium has no editable input; derive proportionally from the serving delta
                    // so saving a resized entry keeps sodium coherent.
                    sodium_mg: this.scaleStoredSodium(inputAmount),
                },
            };
        }

        // Read-only mode: recalculate from per100g or use current data
        const serving = this.calculateServing(inputAmount);
        return { servingAmount, serving };
    }

    private readFloatInput(id: string): number {
        const raw = (this.shadowRoot!.getElementById(id) as HTMLInputElement).value;
        const parsed = Number.parseFloat(raw);
        return Number.isFinite(parsed) ? parsed : 0;
    }

    private scaleStoredSodium(currentAmount: number): number {
        const data = this._data;
        if (!data) return 0;
        if (data.servingByWeight && data.per100g) {
            return (data.per100g.sodium_mg ?? 0) * currentAmount / 100;
        }
        if (!data.servingByWeight && data.servingAmount > 0) {
            const ratio = currentAmount / data.servingAmount;
            return (data.serving.sodium_mg ?? 0) * ratio;
        }
        return data.serving.sodium_mg ?? 0;
    }

    private rebuild(): void {
        const shadow = this.shadowRoot!;
        shadow.adoptedStyleSheets = [styles];
        shadow.replaceChildren();
        const tmpl = this._editable ? editableTemplate : readOnlyTemplate;
        shadow.appendChild(tmpl.content.cloneNode(true));
        this.wireEvents();
        if (this._data) this.populate();
    }

    private wireEvents(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('serving-size')!.addEventListener('input', () => this.onServingChange());
        shadow.getElementById('serving-size')!.addEventListener('change', () => this.onServingChange());
        shadow.getElementById('step-down')!.addEventListener('click', () => this.adjustServing(-1));
        shadow.getElementById('step-up')!.addEventListener('click', () => this.adjustServing(1));

        if (this._editable) {
            // Keep the per-100g reference in sync with the user's direct macro edits.
            for (const id of MACRO_INPUT_IDS) {
                shadow.getElementById(id)?.addEventListener('input', () => this.refreshPer100gFromInputs());
            }
        }
    }

    private populate(): void {
        const data = this._data;
        if (!data) return;
        const shadow = this.shadowRoot!;

        // Serving label
        const label = shadow.getElementById('serving-label')!;
        label.textContent = data.servingByWeight ? 'Serving (g)' : 'Servings';

        // Serving amount
        (shadow.getElementById('serving-size') as HTMLInputElement).value = this.formatAmount(data.servingAmount);
        this._lastServingAmount = data.servingAmount;

        // Macros
        this.renderServing(data.serving);

        // Per-100g reference (shown in both read-only and editable modes when per100g is available)
        const per100Section = shadow.getElementById('per100-section');
        if (per100Section) {
            if (data.per100g) {
                per100Section.hidden = false;
                const refLabel = shadow.getElementById('ref-label')!;
                refLabel.textContent = data.servingByWeight ? 'Per 100g' : 'Per serving';
                shadow.getElementById('cal-100')!.textContent = formatMacro(data.per100g.calories);
                shadow.getElementById('protein-100')!.textContent = formatMacro(data.per100g.protein_g);
                shadow.getElementById('carbs-100')!.textContent = formatMacro(data.per100g.carbs_g);
                shadow.getElementById('fat-100')!.textContent = formatMacro(data.per100g.fat_g);
            } else {
                per100Section.hidden = true;
            }
        }

        // Portion presets
        this.renderPortionPresets();
    }

    /**
     * Rebuild the per-100g display from the current macro inputs, so the
     * reference stays truthful while the user edits macros directly.
     */
    private refreshPer100gFromInputs(): void {
        const shadow = this.shadowRoot!;
        const per100Section = shadow.getElementById('per100-section') as HTMLElement | null;
        if (!per100Section || per100Section.hidden) return;
        if (!this._data?.servingByWeight) return;

        const amount = this.getServingAmount();
        if (amount <= 0) return;
        const scale = 100 / amount;
        shadow.getElementById('cal-100')!.textContent = formatMacro(this.readFloatInput('cal-serving') * scale);
        shadow.getElementById('protein-100')!.textContent = formatMacro(this.readFloatInput('protein-serving') * scale);
        shadow.getElementById('carbs-100')!.textContent = formatMacro(this.readFloatInput('carbs-serving') * scale);
        shadow.getElementById('fat-100')!.textContent = formatMacro(this.readFloatInput('fat-serving') * scale);
    }

    private renderServing(serving: ServingValues): void {
        const shadow = this.shadowRoot!;
        if (this._editable) {
            // Preserve decimals so float-valued macros (e.g., 7.75g protein) survive a round-trip.
            (shadow.getElementById('cal-serving') as HTMLInputElement).value = this.formatNutritionValue(serving.calories);
            (shadow.getElementById('protein-serving') as HTMLInputElement).value = this.formatNutritionValue(serving.protein_g);
            (shadow.getElementById('carbs-serving') as HTMLInputElement).value = this.formatNutritionValue(serving.carbs_g);
            (shadow.getElementById('fat-serving') as HTMLInputElement).value = this.formatNutritionValue(serving.fat_g);
            (shadow.getElementById('fiber-serving') as HTMLInputElement).value = this.formatNutritionValue(serving.fiber_g);
            (shadow.getElementById('sugar-serving') as HTMLInputElement).value = this.formatNutritionValue(serving.sugar_g);
        } else {
            shadow.getElementById('cal-serving')!.textContent = formatMacro(serving.calories);
            shadow.getElementById('protein-serving')!.textContent = formatMacro(serving.protein_g);
            shadow.getElementById('carbs-serving')!.textContent = formatMacro(serving.carbs_g);
            shadow.getElementById('fat-serving')!.textContent = formatMacro(serving.fat_g);
        }
    }

    private onServingChange(): void {
        const amount = this.getServingAmount();
        if (this._editable) {
            // Ratio-based scaling preserves any manual macro overrides the user has made.
            // If the user never touched macros, they scale from the populated values; if
            // they did, their edits become the new baseline.
            if (this._lastServingAmount > 0 && amount > 0 && amount !== this._lastServingAmount) {
                const ratio = amount / this._lastServingAmount;
                const shadow = this.shadowRoot!;
                for (const id of MACRO_INPUT_IDS) {
                    const input = shadow.getElementById(id) as HTMLInputElement | null;
                    if (!input) continue;
                    const current = Number.parseFloat(input.value);
                    if (!Number.isFinite(current)) continue;
                    input.value = this.formatNutritionValue(current * ratio);
                }
            }
            this._lastServingAmount = amount;
            this.refreshPer100gFromInputs();
            return;
        }
        const serving = this.calculateServing(amount);
        this.renderServing(serving);
        this._lastServingAmount = amount;
    }

    private calculateServing(amount: number): ServingValues {
        const data = this._data;
        if (!data) return { calories: 0, protein_g: 0, carbs_g: 0, fat_g: 0, fiber_g: 0, sugar_g: 0, sodium_mg: 0 };

        if (data.per100g && data.servingByWeight) {
            const s = (v: number) => (v * amount) / 100;
            return {
                calories: s(data.per100g.calories),
                protein_g: s(data.per100g.protein_g),
                carbs_g: s(data.per100g.carbs_g),
                fat_g: s(data.per100g.fat_g),
                fiber_g: s(data.per100g.fiber_g ?? 0),
                sugar_g: s(data.per100g.sugar_g ?? 0),
                sodium_mg: s(data.per100g.sodium_mg ?? 0),
            };
        }

        // Multiplier mode. `data.serving` is scaled to `data.servingAmount`
        // (the type's documented contract — same convention scaleStoredSodium
        // already used), so scale by the RATIO of the new count to the initial
        // count. Multiplying absolutely treated a 2.5-serving default as
        // ×2.5 on top of already-scaled macros (story 192).
        const ratio = Math.max(0.1, amount) / (data.servingAmount > 0 ? data.servingAmount : 1);
        return {
            calories: data.serving.calories * ratio,
            protein_g: data.serving.protein_g * ratio,
            carbs_g: data.serving.carbs_g * ratio,
            fat_g: data.serving.fat_g * ratio,
            fiber_g: data.serving.fiber_g * ratio,
            sugar_g: data.serving.sugar_g * ratio,
            sodium_mg: data.serving.sodium_mg * ratio,
        };
    }

    private adjustServing(direction: 1 | -1): void {
        const shadow = this.shadowRoot!;
        const input = shadow.getElementById('serving-size') as HTMLInputElement;
        const current = Number.parseFloat(input.value) || 0;
        const step = this._data?.servingByWeight
            ? OpenFoodFactsService.getServingStep(current)
            : 1;
        input.value = this.formatAmount(Math.max(0.1, current + direction * step));
        this.onServingChange();
    }

    private renderPortionPresets(): void {
        const container = this.shadowRoot!.getElementById('portion-presets')!;
        container.replaceChildren();
        const data = this._data;
        if (!data?.servingByWeight) return;

        const presets = OpenFoodFactsService.getPortionPresets(data.servingAmount);
        for (const preset of presets) {
            const btn = document.createElement('button');
            btn.className = 'preset-btn';
            btn.type = 'button';
            btn.textContent = `x${preset.multiplier} (${preset.grams}g)`;
            btn.addEventListener('click', () => {
                const input = this.shadowRoot!.getElementById('serving-size') as HTMLInputElement;
                const current = Number.parseFloat(input.value) || data.servingAmount;
                input.value = this.formatAmount(Math.max(0.1, current * preset.multiplier));
                this.onServingChange();
            });
            container.appendChild(btn);
        }
    }

    private getServingAmount(): number {
        const input = this.shadowRoot!.getElementById('serving-size') as HTMLInputElement;
        return Math.max(0.1, Number.parseFloat(input.value) || 0.1);
    }

    private formatNutritionValue(value: number): string {
        return Number(value.toFixed(2)).toString();
    }

    private formatAmount(value: number): string {
        return Number(value.toFixed(2)).toString();
    }
}

customElements.define('food-serving-form', FoodServingForm);
