import type { Per100gNutrition, FoodItem, ConsumptionEntry, NutritionEstimate } from '@motivation/shared';
import { OpenFoodFactsService } from '../../../services/openfoodfacts.service.js';
import type { OFFProduct } from '../../../services/openfoodfacts.service.js';

export interface ServingValues {
    calories: number;
    protein_g: number;
    carbs_g: number;
    fat_g: number;
    fiber_g: number;
    sugar_g: number;
    sodium_mg: number;
}

export interface FoodServingFormData {
    /** Per-100g base values for proportional recalculation. Null when only fixed-serving data is available. */
    per100g: Per100gNutrition | null;
    /** Current serving nutrition (already scaled to servingAmount). */
    serving: ServingValues;
    /** Default serving amount — grams when servingByWeight is true, otherwise a multiplier. */
    servingAmount: number;
    /** True = grams mode with adaptive step sizes. False = multiplier mode (step = 1). */
    servingByWeight: boolean;
    /** Display label for multiplier mode (e.g. "1 serving"). */
    servingLabel?: string;
    /**
     * Base units per ONE serving (the food item's `base_amount`; 100 in the
     * per-100g modes). Persisted amounts (`consumption_entries.amount`,
     * `food_items.default_serving_amount`, meal-ingredient amounts) are ALWAYS
     * in base units system-wide; the multiplier shown in the UI is amount /
     * baseAmount. Treating a base-unit default as a raw multiplier is how an
     * untouched Chocomel save logged 20,500 kcal — story 192.
     */
    baseAmount: number;
}

function scalePer100g(per100g: Per100gNutrition, grams: number): ServingValues {
    const s = (v: number) => (v * grams) / 100;
    return {
        calories: s(per100g.calories),
        protein_g: s(per100g.protein_g),
        carbs_g: s(per100g.carbs_g),
        fat_g: s(per100g.fat_g),
        fiber_g: s(per100g.fiber_g ?? 0),
        sugar_g: s(per100g.sugar_g ?? 0),
        sodium_mg: s(per100g.sodium_mg ?? 0),
    };
}

function backCalcPer100g(serving: ServingValues, grams: number): Per100gNutrition {
    const scale = 100 / grams;
    return {
        calories: serving.calories * scale,
        protein_g: serving.protein_g * scale,
        carbs_g: serving.carbs_g * scale,
        fat_g: serving.fat_g * scale,
        fiber_g: serving.fiber_g * scale,
        sugar_g: serving.sugar_g * scale,
        sodium_mg: serving.sodium_mg * scale,
    };
}

function foodItemToPer100g(item: FoodItem): Per100gNutrition | null {
    // FoodItem stores nutrient densities per `base_amount` in `base_unit`.
    // For weight-based foods (g) we can normalize directly to per-100g.
    // Volume-based and piece-based items have no per-100g representation.
    if (item.base_unit !== 'g' || !item.base_amount || item.base_amount <= 0) {
        return null;
    }
    if (item.calories_per_base === undefined && item.protein_g_per_base === undefined) {
        return null;
    }
    const factor = 100 / item.base_amount;
    return {
        calories: (item.calories_per_base ?? 0) * factor,
        protein_g: (item.protein_g_per_base ?? 0) * factor,
        carbs_g: (item.carbs_g_per_base ?? 0) * factor,
        fat_g: (item.fat_g_per_base ?? 0) * factor,
        fiber_g: (item.fiber_g_per_base ?? 0) * factor,
        sugar_g: (item.sugar_g_per_base ?? 0) * factor,
        sodium_mg: (item.sodium_mg_per_base ?? 0) * factor,
    };
}

export function offProductToFormData(product: OFFProduct): FoodServingFormData {
    const defaultGrams = OpenFoodFactsService.getDefaultServing(product);
    const per100g: Per100gNutrition = {
        calories: product.calories_per_100g,
        protein_g: product.protein_per_100g,
        carbs_g: product.carbs_per_100g,
        fat_g: product.fat_per_100g,
        fiber_g: product.fiber_per_100g,
        sugar_g: product.sugar_per_100g,
        sodium_mg: product.sodium_per_100g * 1000,
    };
    return {
        per100g,
        serving: scalePer100g(per100g, defaultGrams),
        servingAmount: defaultGrams,
        servingByWeight: true,
        baseAmount: 100,
    };
}

/**
 * `initialAmount` overrides the food item's default — used when re-opening the
 * form for an already-chosen amount (e.g. editing an existing meal ingredient).
 */
export function foodItemToFormData(item: FoodItem, initialAmount?: number): FoodServingFormData {
    const per100g = foodItemToPer100g(item);
    if (per100g) {
        const fallbackGrams = item.default_serving_amount && item.default_serving_amount > 0
            ? Math.round(item.default_serving_amount)
            : item.serving_quantity && item.serving_quantity > 0
                ? Math.round(item.serving_quantity)
                : 100;
        const grams = initialAmount && initialAmount > 0 ? initialAmount : fallbackGrams;
        return {
            per100g,
            serving: scalePer100g(per100g, grams),
            servingAmount: grams,
            servingByWeight: true,
            baseAmount: 100,
        };
    }
    // Non-gram base_unit: per-base values represent one serving of
    // `base_amount` `base_unit` (e.g. one piece, 100ml). Persisted amounts
    // (default_serving_amount, initialAmount from entries/ingredients) are in
    // BASE UNITS — convert to the serving multiplier the form displays, and
    // scale the macros to it (story 192: 250ml default on a per-100ml item is
    // 2.5 servings, not 250).
    const baseAmount = item.base_amount > 0 ? item.base_amount : 1;
    const amountInBaseUnits = initialAmount && initialAmount > 0
        ? initialAmount
        : item.default_serving_amount && item.default_serving_amount > 0
            ? item.default_serving_amount
            : baseAmount; // one serving
    const multiplier = amountInBaseUnits / baseAmount;
    const perServing = {
        calories: item.calories_per_base ?? 0,
        protein_g: item.protein_g_per_base ?? 0,
        carbs_g: item.carbs_g_per_base ?? 0,
        fat_g: item.fat_g_per_base ?? 0,
        fiber_g: item.fiber_g_per_base ?? 0,
        sugar_g: item.sugar_g_per_base ?? 0,
        sodium_mg: item.sodium_mg_per_base ?? 0,
    };
    return {
        per100g: null,
        serving: {
            calories: perServing.calories * multiplier,
            protein_g: perServing.protein_g * multiplier,
            carbs_g: perServing.carbs_g * multiplier,
            fat_g: perServing.fat_g * multiplier,
            fiber_g: perServing.fiber_g * multiplier,
            sugar_g: perServing.sugar_g * multiplier,
            sodium_mg: perServing.sodium_mg * multiplier,
        },
        servingAmount: multiplier,
        servingByWeight: false,
        servingLabel: item.serving_label ?? `${item.base_amount} ${item.base_unit}`,
        baseAmount,
    };
}

/**
 * Build form data from an existing consumption entry combined with its referenced
 * food item. The entry already snapshots the macros at log time; the food item
 * provides the per-100g context so the user can adjust the amount and have the
 * macros scale predictably.
 */
export function consumptionEntryToFormData(entry: ConsumptionEntry, foodItem: FoodItem): FoodServingFormData {
    const serving: ServingValues = {
        calories: entry.calories ?? 0,
        protein_g: entry.protein_g ?? 0,
        carbs_g: entry.carbs_g ?? 0,
        fat_g: entry.fat_g ?? 0,
        fiber_g: entry.fiber_g ?? 0,
        sugar_g: entry.sugar_g ?? 0,
        sodium_mg: entry.sodium_mg ?? 0,
    };
    const per100g = foodItemToPer100g(foodItem);
    if (per100g) {
        return {
            per100g,
            serving,
            servingAmount: entry.amount,
            servingByWeight: true,
            baseAmount: 100,
        };
    }
    // entry.amount is in base units; the form displays servings (story 192).
    const baseAmount = foodItem.base_amount > 0 ? foodItem.base_amount : 1;
    return {
        per100g: null,
        serving,
        servingAmount: entry.amount / baseAmount,
        servingByWeight: false,
        servingLabel: foodItem.serving_label ?? `${foodItem.base_amount} ${foodItem.base_unit}`,
        baseAmount,
    };
}

export function estimateToFormData(estimate: NutritionEstimate): FoodServingFormData {
    // The AI returns per-base nutrients aligned to base_amount/base_unit.
    // For weight-based estimates (the only kind the model is told to produce),
    // we can build per-100g directly without back-calculation.
    const per100g: Per100gNutrition | null = estimate.base_unit === 'g' && estimate.base_amount > 0
        ? {
            calories: (estimate.calories_per_base * 100) / estimate.base_amount,
            protein_g: (estimate.protein_g_per_base * 100) / estimate.base_amount,
            carbs_g: (estimate.carbs_g_per_base * 100) / estimate.base_amount,
            fat_g: (estimate.fat_g_per_base * 100) / estimate.base_amount,
            fiber_g: (estimate.fiber_g_per_base * 100) / estimate.base_amount,
            sugar_g: (estimate.sugar_g_per_base * 100) / estimate.base_amount,
            sodium_mg: (estimate.sodium_mg_per_base * 100) / estimate.base_amount,
        }
        : null;
    const grams = estimate.default_serving_amount > 0 ? estimate.default_serving_amount : 100;
    const factor = grams / estimate.base_amount;
    const serving: ServingValues = {
        calories: estimate.calories_per_base * factor,
        protein_g: estimate.protein_g_per_base * factor,
        carbs_g: estimate.carbs_g_per_base * factor,
        fat_g: estimate.fat_g_per_base * factor,
        fiber_g: estimate.fiber_g_per_base * factor,
        sugar_g: estimate.sugar_g_per_base * factor,
        sodium_mg: estimate.sodium_mg_per_base * factor,
    };
    const servingByWeight = estimate.base_unit === 'g';
    const baseAmount = servingByWeight ? 100 : (estimate.base_amount > 0 ? estimate.base_amount : 1);
    return {
        per100g,
        serving,
        // Weight mode displays grams; multiplier mode displays servings of
        // base_amount base units (story 192).
        servingAmount: servingByWeight ? grams : grams / baseAmount,
        servingByWeight,
        baseAmount,
    };
}
